create extension if not exists pgcrypto;
create table public.profiles (id uuid primary key default gen_random_uuid(), user_id uuid not null unique references auth.users(id) on delete cascade, display_name text, birth_date date, height numeric, weight numeric, goals jsonb default '[]', preferences jsonb default '{}', created_at timestamptz default now(), updated_at timestamptz default now());
create table public.daily_entries (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, entry_date date not null, original_text text not null, ai_summary text, mood_score smallint check(mood_score between 0 and 10), energy_score smallint check(energy_score between 0 and 10), focus_score smallint check(focus_score between 0 and 10), sleep_hours numeric check(sleep_hours between 0 and 24), sleep_quality_score smallint check(sleep_quality_score between 0 and 10), difficulty_starting_score smallint check(difficulty_starting_score between 0 and 10), hydration_liters numeric check(hydration_liters between 0 and 15), trained boolean, worked_or_studied_minutes integer check(worked_or_studied_minutes between 0 and 1440), excessive_phone_use boolean, notes text, next_action text, tags text[] default '{}', created_at timestamptz default now(), updated_at timestamptz default now(), unique(user_id,entry_date));
create table public.meals (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, daily_entry_id uuid not null references daily_entries(id) on delete cascade, meal_type text, description text not null, approximate_time time, quality_score smallint check(quality_score between 0 and 10), protein_grams numeric, calories numeric, created_at timestamptz default now());
create table public.activities (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, daily_entry_id uuid references daily_entries(id) on delete cascade, activity_type text, description text not null, duration_minutes integer, completed boolean, created_at timestamptz default now());
create table public.achievements (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, daily_entry_id uuid not null references daily_entries(id) on delete cascade, description text not null, created_at timestamptz default now());
create table public.difficulties (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, daily_entry_id uuid not null references daily_entries(id) on delete cascade, description text not null, created_at timestamptz default now());
create table public.habits (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null, description text, frequency jsonb default '{}', active boolean default true, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.habit_logs (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, habit_id uuid not null references habits(id) on delete cascade, log_date date not null, completed boolean default false, notes text, created_at timestamptz default now(), unique(habit_id,log_date));
create table public.routine_markers (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null, scheduled_time time, instruction text, frequency jsonb default '{}', active boolean default true, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.routine_logs (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, routine_marker_id uuid not null references routine_markers(id) on delete cascade, log_date date not null, completed_at timestamptz, status text check(status in ('pending','completed','skipped')), created_at timestamptz default now());
create table public.conversations (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, title text, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.messages (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, conversation_id uuid not null references conversations(id) on delete cascade, role text not null check(role in ('user','assistant','system')), content text not null, metadata jsonb default '{}', created_at timestamptz default now());
create table public.weekly_reports (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, week_start date not null, week_end date not null, report text not null, structured_data jsonb default '{}', created_at timestamptz default now(), unique(user_id,week_start));
create table public.user_memories (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, category text not null, content text not null, importance smallint default 5 check(importance between 0 and 10), source_entry_id uuid references daily_entries(id) on delete set null, active boolean default true, created_at timestamptz default now(), updated_at timestamptz default now());
create index daily_entries_user_date_idx on daily_entries(user_id,entry_date desc); create index messages_conversation_created_idx on messages(conversation_id,created_at); create index weekly_reports_user_week_idx on weekly_reports(user_id,week_start desc); create index user_memories_user_active_idx on user_memories(user_id,active);
do $$ declare t text; begin foreach t in array array['profiles','daily_entries','meals','activities','achievements','difficulties','habits','habit_logs','routine_markers','routine_logs','conversations','messages','weekly_reports','user_memories'] loop execute format('alter table public.%I enable row level security',t); execute format('create policy "owner_all" on public.%I for all using (auth.uid() = user_id) with check (auth.uid() = user_id)',t); end loop; end $$;
create or replace function public.set_updated_at() returns trigger language plpgsql security invoker set search_path='' as $$ begin new.updated_at=now(); return new; end $$;
do $$ declare t text; begin foreach t in array array['profiles','daily_entries','habits','routine_markers','conversations','user_memories'] loop execute format('create trigger set_updated_at before update on public.%I for each row execute function public.set_updated_at()',t); end loop; end $$;

